SELECT COUNT(*) AS total_outcomes
FROM treatment_outcomes
WHERE outcome_description LIKE '%reduction in anxiety%';

SELECT intervention_name, duration
FROM interventions
WHERE duration = (SELECT MIN(duration) FROM interventions);

SELECT DISTINCT p.first_name
FROM participants p
WHERE p.participant_id IN (
    SELECT participant_id FROM participant_interventions
) AND p.participant_id IN (
    SELECT participant_id FROM assessments
    GROUP BY participant_id
    HAVING COUNT(assessment_id) >= 2
);
